#include <iostream>
#include <algorithm>
#include <vector>

using namespace std;

/*
	function to solve task 1.
	knapsack problem.
*/
int task1(int n, int m, int x, vector<int> &p, vector<int> &w) {
	vector<vector<int>> dp(m + 1, vector<int>(x * n + 1, 0));

	// base case
	for (int cap = 0; cap <= x * n; ++cap) {
		dp[0][cap] = 0;
	}

	// general case
	for (int i = 1; i <= m; ++i) {
		for (int cap = 0; cap <= x * n; ++cap) {
			// not using the i object => the solution is the one from the
			// prev step (i - 1)
			dp[i][cap] = dp[i - 1][cap];

			// using the object i - 1 => need budget for the i object, therefore
			// cap - p[i - 1] >= 0
			if (cap - p[i - 1] >= 0) {
				int sol_aux = dp[i - 1][cap - p[i - 1]] + w[i - 1];

				dp[i][cap] = max(dp[i][cap], sol_aux);
			}
		}
	}

	return dp[m][x * n];
}
/*
	function to solve task2.
	same implementation as task1 but with different parametters.
*/
int task2(int n, int m, int x, vector<int> &p, vector<int> &w) {
	vector<int> double_p;

	double_p.insert(double_p.end(), p.begin(), p.end());
	double_p.insert(double_p.end(), p.begin(), p.end());

	vector<int> double_w;

	double_w.insert(double_w.end(), w.begin(), w.end());
	double_w.insert(double_w.end(), w.begin(), w.end());

	return task1(n, 2 * m, x, double_p, double_w);
}

int task3(int n, int m, int x, vector<int> &p, vector<int> &w) {
	vector<int> double_p;
	double_p.insert(double_p.end(), p.begin(), p.end());
	double_p.insert(double_p.end(), p.begin(), p.end());

	vector<int> double_w;
	double_w.insert(double_w.end(), w.begin(), w.end());
	double_w.insert(double_w.end(), w.begin(), w.end());

	int double_m = 2 * m;

	vector<vector<vector<int>>> dp(n + 1, vector<vector<int>>(double_m + 1,
	vector<int>(x * n + 1, 0)));

	// base case
	for (int i = 0; i < n; i++) {
		for (int cap = 0; cap <= x * n; ++cap) {
			dp[i][0][cap] = 0;
		}
	}

	// general case
	for (int nr = 1; nr <= n; nr++) {
		for (int i = 1; i <= double_m; ++i) {
			for (int cap = 0; cap <= x * n; ++cap) {
				dp[nr][i][cap] = dp[nr][i - 1][cap];
				if (cap - double_p[i - 1] >= 0) {
					int sol_aux = dp[nr - 1][i - 1][cap - double_p[i - 1]] + double_w[i - 1];

					dp[nr][i][cap] = max(dp[nr][i][cap], sol_aux);
				}
			}
		}
	}

	int max = 0;
	for (int i = 0; i <= n; i++) {
		if (max < dp[i][double_m][x * n]) {
			max = dp[i][double_m][x * n];
		}
	}

	return max;
}

int main() {
	freopen("sushi.in", "r", stdin);
	freopen("sushi.out", "w", stdout);

	int task;  // task number

	int n;  // number of friends
	int m;  // number of sushi types
	int x;  // how much each of you is willing to spend

	vector<int> prices;  // prices of each sushi type
	// the grades you and your friends gave to each sushi type
	vector<vector<int>> grades;

	cin >> task;
	cin >> n >> m >> x;

	prices.assign(m, 0);
	grades.assign(n, vector<int>(m, 0));

	// price of each sushi
	for (int i = 0; i < m; ++i) {
		cin >> prices[i];
	}

	// each friends rankings of sushi types
	for (int i = 0; i < n; ++i) {
		for (int j = 0; j < m; ++j) {
			cin >> grades[i][j];
		}
	}

	vector<int> w(m, 0);
	for (int j = 0; j < m; j++) {
		for (int i = 0; i < n; i++) {
			w[j] += grades[i][j];
		}
	}

	int ans = -1;

	switch (task) {
	case 1:
		ans = task1(n, m, x, prices, w);
		break;
	case 2:
		ans = task2(n, m, x, prices, w);
		break;
	case 3:
		ans = task3(n, m, x, prices, w);
		break;
	default:
		cout << "wrong task number" << endl;
	}

	cout << ans << endl;

	return 0;
}

import java.io.File;
import java.io.FileNotFoundException;
import java.io.FileWriter;
import java.io.IOException;
import java.util.Scanner;

class Sushi {

	static int n, m, x;
	static int[] prices;
	static int[][] grades;

	Sushi(){}

	static int task1() {
		// Insumare note pentru fiecare platou -> O(m * n)
		int[] grades_sum = new int[m + 1];
		for (int i = 1; i <= m; i++) {
			grades_sum[i] = 0;
			for (int j = 0; j < n; j++) {
				grades_sum[i] += grades[j][i];
			}
		}

		// Conditii initiale -> O(n * x)
		int[][] dp = new int[m + 1][n * x + 1];
		for (int i = 0; i <= n * x; i++) {
			dp[0][i] = 0;
		}

		// Parcurgerea matricii pentru a rezolva plecand de la caz banal -> O(m * n * x)
		for (int i = 1; i <= m; i++) {
			for (int j = 0; j <= n * x; j++) {
				if (j - prices[i] >= 0) {
					if (dp[i - 1][j - prices[i]] + grades_sum[i] > dp[i - 1][j]) {
						dp[i][j] = dp[i - 1][j - prices[i]] + grades_sum[i];
					} else {
						dp[i][j] = dp[i - 1][j];
					}
				} else {
					dp[i][j] = dp[i - 1][j];
				}
			}
		}

		return dp[m][n * x];
	}

	static int task2() {
		// Insumare note pentru fiecare platou -> O(m * n)
		int[] grades_sum = new int[m + 1];
		for (int i = 1; i <= m; i++) {
			grades_sum[i] = 0;
			for (int j = 0; j < n; j++) {
				grades_sum[i] += grades[j][i];
			}
		}

		// Conditii initiale -> O(n * x)
		int[][] dp = new int[m + 1][n * x + 1];
		for (int i = 0; i <= n * x; i++) {
			dp[0][i] = 0;
		}

		// Parcurgerea matricii pentru a rezolva plecand de la caz banal -> O(m * n * x)
		for (int i = 1; i <= m; i++) {
			for (int j = 0; j <= n * x; j++) {
				int nr = 1;
				int best = dp[i - 1][j];

				// Parcurgere cu adaugarea a maxim 2 platouri de tip i
				while (j - nr * prices[i] >= 0 && nr <= 2) {
					best = max(best, dp[i - 1][j - nr * prices[i]] + nr * grades_sum[i]);
					nr ++;
				}
				dp[i][j] = best;
			}
		}

		return dp[m][n * x];
	}

	static int task3() {
		// Insumare note pentru fiecare platou -> O(m * n)
		int[] grades_sum = new int[m + 1];
		for (int i = 1; i <= m; i++) {
			grades_sum[i] = 0;
			for (int j = 0; j < n; j++) {
				grades_sum[i] += grades[j][i];
			}
		}

		// Conditii initiale -> O(n^2 *x)
		int[][][] dp = new int[m + 1][n * x + 1][n + 1];
		for (int i = 0; i <= n * x; i++) {
			for (int j = 0; j <= n; j++) {
				dp[0][i][j] = 0;
			}
		}

		// Parcurgerea matricii pentru a rezolva plecand de la caz banal -> O(m * n * x * n)
		for (int i = 1; i <= m; i++) {
			for (int j = 0; j <= n * x; j++) {
				for (int k = 0; k <= n; k++) {
					int nr = 1;
					int best = dp[i - 1][j][k];

					// Parcurgere cu adaugarea a maxim 2 platouri de tip i
					while (j - nr * prices[i] >= 0 && nr <= 2 && nr <= k) {
						if (dp[i - 1][j - nr * prices[i]][k - nr] + nr * grades_sum[i] > best) {
							best = dp[i - 1][j - nr * prices[i]][k - nr] + nr * grades_sum[i];
						}
						nr ++;
					}
					dp[i][j][k] = best;
				}
			}
		}

		return dp[m][n * x][n];
	}

	// Functie de determinat maximul a doi intregi
	static int max(int a, int b) {
		if (a > b) {
			return a;
		}
		return b;
	}

	public static void main(String[] args) {
		try {
			Scanner sc = new Scanner(new File("sushi.in"));

			final int task = sc.nextInt(); // task number

			n = sc.nextInt(); // number of friends
			m = sc.nextInt(); // number of sushi types
			x = sc.nextInt(); // how much each of you is willing to spend

			prices = new int[m + 1]; // prices of each sushi type
			grades = new int[n][m + 1]; // the grades you and your friends gave to each sushi type

			// price of each sushi
			for (int i = 1; i <= m; i++) {
				prices[i] = sc.nextInt();
			}

			// each friends rankings of sushi types
			for (int i = 0; i < n; i++) {
				for (int j = 1; j <= m; j++) {
					grades[i][j] = sc.nextInt();
				}
			}

			int ans;
			switch (task) {
				case 1:
					ans = Sushi.task1();
					break;
				case 2:
					ans = Sushi.task2();
					break;
				case 3:
					ans = Sushi.task3();
					break;
				default:
					ans = -1;
					System.out.println("wrong task number");
			}

			try {
				FileWriter fw = new FileWriter("sushi.out");
				fw.write(Integer.toString(ans) + '\n');
				fw.close();

			} catch (IOException e) {
				System.out.println(e.getMessage());
			}

			sc.close();
		} catch (FileNotFoundException e) {
			System.out.println(e.getMessage());
		}
	}
}
